BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?spec ?specType WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("APS")))

  OPTIONAL {
    ?req vocab:constraint ?spec .
    ?spec rdf:type ?specType .
  }
  OPTIONAL {
    ?req vocab:specification ?spec .
    ?spec rdf:type ?specType .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqName ?tcType ?interval ?min ?max ?expr ?when WHERE {
  ?req rdf:type vocab:tmt%20requirement ;
       vocab:NamedElement_name ?reqName .

  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("APS")))

  ?req vocab:constraint ?spec .
  ?spec rdf:type ?tcType .

  # TimeConstraint -> specification__from_TimeConstraint -> (constraint specification back reference patterns)
  OPTIONAL {
    ?spec vocab:specification__from_DurationConstraint ?durSpec .
    ?durSpec rdf:type ?durType .
  }

  OPTIONAL {
    ?spec rdf:type vocab:TimeConstraint .
    ?spec vocab:specification__from_TimeConstraint ?spec2 .
  }

  # DurationInterval/TimeInterval bounds
  OPTIONAL { ?tcType rdf:type vocab:Interval . }

  OPTIONAL {
    ?spec vocab:min ?min .
    ?spec vocab:max ?max .
  }

  OPTIONAL {
    ?spec vocab:expr ?expr .
  }

  OPTIONAL {
    ?spec vocab:when ?when .
  }

  OPTIONAL { ?spec vocab:_timeIntervalOfMin ?interval . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqName ?spec ?specType ?specName ?body ?expr WHERE {
  ?req rdf:type vocab:tmt%20requirement ;
       vocab:NamedElement_name ?reqName ;
       vocab:constraint ?spec .

  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("APS")))

  ?spec rdf:type ?specType .
  OPTIONAL { ?spec vocab:NamedElement_name ?specName . }
  OPTIONAL { ?spec vocab:body ?body . }
  OPTIONAL { ?spec vocab:expr ?expr . }

  FILTER(
    (BOUND(?specName) && CONTAINS(LCASE(STR(?specName)), "time")) ||
    (BOUND(?body) && CONTAINS(LCASE(STR(?body)), "time")) ||
    (BOUND(?expr) && CONTAINS(LCASE(STR(?expr)), "time")) ||
    (BOUND(?specName) && CONTAINS(LCASE(STR(?specName)), "duration")) ||
    (BOUND(?body) && CONTAINS(LCASE(STR(?body)), "duration")) ||
    (BOUND(?expr) && CONTAINS(LCASE(STR(?expr)), "duration")) ||
    (BOUND(?specName) && CONTAINS(LCASE(STR(?specName)), "interval")) ||
    (BOUND(?body) && CONTAINS(LCASE(STR(?body)), "interval")) ||
    (BOUND(?expr) && CONTAINS(LCASE(STR(?expr)), "interval"))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop (COUNT(*) AS ?count) WHERE {
  ?req rdf:type vocab:tmt%20requirement ;
       vocab:NamedElement_name ?reqName ;
       vocab:constraint ?spec .

  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("APS%20Template%20Requirement")))

  ?req ?prop ?val .
} 
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqName ?valType ?valStr WHERE {
  ?req rdf:type vocab:tmt%20requirement ;
       vocab:NamedElement_name ?reqName .
  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("APS")))

  # Look for element value objects
  ?req vocab:Element__elementValueOfElement ?ev .
  ?ev rdf:type ?valType .

  # Try common name/value predicates
  OPTIONAL { ?ev vocab:NamedElement_name ?valStr . }
  OPTIONAL { ?ev vocab:LiteralString_value ?valStr . }
  OPTIONAL { ?ev vocab:value ?valStr . }
  OPTIONAL { ?ev vocab:Slot_value ?valStr . }

  FILTER(
    BOUND(?valStr) && (
      CONTAINS(LCASE(STR(?valStr)), "time") ||
      CONTAINS(LCASE(STR(?valStr)), "duration") ||
      CONTAINS(LCASE(STR(?valStr)), "interval")
    )
  )
}
LIMIT 25
